#!/usr/bin/env node
// Generates manifest.txt for the zeon-assets repo: one `relative/path<space>shorthash`
// line per asset file. The ZeoN menu lib (remote_assets.lua) fetches this once per session,
// diffs it against the copy cached on disk, and re-downloads ONLY the assets whose hash
// changed. That lets a changed-but-same-name image reach users without re-downloading
// everything on every launch.
//
// Run from the repo root: `node .github/scripts/gen-manifest.mjs`
// No external dependencies (Node >= 16).

import { createHash } from "node:crypto";
import { readdirSync, readFileSync, writeFileSync, statSync } from "node:fs";
import { join, relative, sep } from "node:path";

const ROOT = process.cwd();
const MANIFEST_NAME = "manifest.txt";
const HASH_LEN = 12;

// Directories never walked (VCS + CI tooling). Add more here if needed.
const SKIP_DIRS = new Set([".git", ".github", "node_modules", "apep"]);
// Files excluded from the manifest (docs + the manifest itself).
const SKIP_FILES = new Set([MANIFEST_NAME, "README.md", "LICENSE", ".gitignore", ".gitattributes"]);

/** @param {string} dir @param {string[]} out */
function walk(dir, out) {
  for (const name of readdirSync(dir)) {
    const abs = join(dir, name);
    const st = statSync(abs);
    if (st.isDirectory()) {
      if (!SKIP_DIRS.has(name)) walk(abs, out);
    } else if (st.isFile()) {
      if (!SKIP_FILES.has(name)) out.push(abs);
    }
  }
}

/** @param {string} abs */
function shortHash(abs) {
  return createHash("sha1").update(readFileSync(abs)).digest("hex").slice(0, HASH_LEN);
}

function main() {
  /** @type {string[]} */
  const files = [];
  walk(ROOT, files);

  const lines = files
    .map((abs) => {
      const rel = relative(ROOT, abs).split(sep).join("/");
      return `${rel} ${shortHash(abs)}`;
    })
    .sort((a, b) => a.localeCompare(b));

  const header = "# Auto-generated by .github/scripts/gen-manifest.mjs - do not edit by hand.\n";
  const body = lines.join("\n") + "\n";
  writeFileSync(join(ROOT, MANIFEST_NAME), header + body, "utf8");

  console.log(`Wrote ${MANIFEST_NAME} with ${lines.length} assets.`);
}

main();
